#include <stdio.h>
#include <string.h>

#define N 10

int n;
char grid[N][N];

void solve(int row) {
    if (row == n) {
        // print the grid
        for (int i = 0; i < n; i++) {
            printf("%s\n", grid[i]);
        }
        return;
    }

    for (int col = 0; col < n; col++) {
        if (grid[row][col] == '0') {
            grid[row][col] = '1';
            solve(row + 1);
            grid[row][col] = '0';
        }
    }
}

int main() {
    scanf("%d", &n);
    for (int i = 0; i < n; i++) {
        scanf("%s", grid[i]);
    }
    solve(0);
    return 0;
}

