using namespace std;

const int N = 10;

void solve(vector<string>& grid, int row) {
    if (row == grid.size()) {
        // print the grid
        for (const auto& str : grid) {
            cout << str << endl;
        }
        return;
    }

    for (int col = 0; col < grid.size(); col++) {
        if (grid[row][col] == '0') {
            grid[row][col] = '1';
            solve(grid, row + 1);
            grid[row][col] = '0';
        }
    }
}

int main() {
    int n;
    cin >> n;
    vector<string> grid(n);
    for (auto& str : grid) {
        cin >> str;
    }
    solve(grid, 0);
    return 0;
}

