const readline = require('readline');

const rl = readline.createInterface({
    input: process.stdin,
    output: process.stdout
});

let n;
let grid;
let inputCount = 0;

rl.on('line', (input) => {
    if (inputCount === 0) {
        n = parseInt(input);
        grid = new Array(n);
        inputCount++;
    } else {
        grid[inputCount - 1] = input.split('');
        inputCount++;
        if (inputCount > n) {
            solve(grid, 0);
            rl.close();
        }
    }
});

function solve(grid, row) {
    if (row === grid.length) {
        // print the grid
        for (let i = 0; i < grid.length; i++) {
            console.log(grid[i].join(''));
        }
        return;
    }

    for (let col = 0; col < grid.length; col++) {
        if (grid[row][col] === '0') {
            grid[row][col] = '1';
            solve(grid, row + 1);
            grid[row][col] = '0';
        }
    }
}

